  el(32,39,21,18,'#e03020');
  // ── Cream belly ──
  el(32,44,14,12,'#a07040');el(32,44,13,11,'#e8c888');el(32,44,10,8,'#f8e0a8');
  // ── Arms ──
  el(10,44,7,5,'#600808',-0.5);el(10,44,6,4,'#c01818',-0.5);
  el(54,44,7,5,'#600808',0.5);el(54,44,6,4,'#c01818',0.5);
  // Claws
  for(let i=0;i<3;i++){ci(5+i*3,50,2,'#d0a030');}
  for(let i=0;i<3;i++){ci(53+i*3,50,2,'#d0a030');}
  // ── Legs ──
  el(22,58,9,7,'#600808');el(22,58,8,6,'#c01818');
